class Solution:
    def decodeString(self, s: str) -> str:
        num_stack: list[int] = []      # 存遇到 '[' 时的重复次数
        str_stack: list[str] = []      # 存遇到 '[' 时已拼好的外层字符串
        cur, k = "", 0                 # cur:当前层字符串;k:正在读的数字
        for c in s:
            if c.isdigit():
                k = k * 10 + int(c)    # 多位数逐位累积
            elif c == "[":             # 进入一层:把 k 和 cur 压栈并清零
                num_stack.append(k); k = 0
                str_stack.append(cur); cur = ""
            elif c == "]":             # 出一层:外层串 + 当前串重复 k 次
                cur = str_stack.pop() + cur * num_stack.pop()
            else:
                cur += c               # 普通字母接到当前串
        return cur
